@SuppressLint("UnrememberedMutableState", "StringFormatInvalid")
@Composable
fun Queue(state: BottomSheetState, playerBottomSheetState: BottomSheetState, navController: NavController, modifier: Modifier = Modifier, backgroundColor: Color, onBackgroundColor: Color, textBackgroundColor: Color) {
    val context = LocalContext.current; val haptic = LocalHapticFeedback.current; val clipboardManager = LocalClipboardManager.current; val menuState = LocalMenuState.current
    val playerConnection = LocalPlayerConnection.current ?: return
    val isPlaying by playerConnection.isPlaying.collectAsState(); val repeatMode by playerConnection.repeatMode.collectAsState(); val currentWindowIndex by playerConnection.currentWindowIndex.collectAsState()
    val mediaMetadata by playerConnection.mediaMetadata.collectAsState(); val currentFormat by playerConnection.currentFormat.collectAsState(initial = null)
    val queueWindows by playerConnection.queueWindows.collectAsState(); val automix by playerConnection.service.automixItems.collectAsState()
    val currentSong by playerConnection.currentSong.collectAsState(initial = null)
    val selectedSongs = remember { mutableStateListOf<MediaMetadata>() }; val selectedItems = remember { mutableStateListOf<Timeline.Window>() }
    var selection by remember { mutableStateOf(false) }; var showDetailsDialog by rememberSaveable { mutableStateOf(false) }
    var locked by rememberPreference(QueueEditLockKey, true); val (enableHapticFeedback) = rememberPreference(booleanPreferencesKey("enable_haptic_feedback"), true)
    val (showCodecOnPlayer) = rememberPreference(booleanPreferencesKey("show_codec_on_player"), false); val (playerDesignStyle) = rememberPreference(intPreferencesKey("player_design_style"), 4)
    var infiniteQueueEnabled by rememberPreference(booleanPreferencesKey("auto_load_more"), true)
    val snackbarHostState = remember { SnackbarHostState() }; var dismissJob: Job? by remember { mutableStateOf(null) }; val coroutineScope = rememberCoroutineScope()
    var showSleepTimerDialog by remember { mutableStateOf(false) }; var sleepTimerValue by remember { mutableFloatStateOf(30f) }; var sleepTimerTimeLeft by remember { mutableLongStateOf(0L) }
    val sleepTimerEnabled = remember(playerConnection.service.sleepTimer.triggerTime, playerConnection.service.sleepTimer.pauseWhenSongEnd) { playerConnection.service.sleepTimer.isActive }
    
    fun clearSelection() { selection = false; selectedSongs.clear(); selectedItems.clear() }
    if (selection) BackHandler { clearSelection() }
    LaunchedEffect(sleepTimerEnabled) { if (sleepTimerEnabled) while (isActive) { sleepTimerTimeLeft = if (playerConnection.service.sleepTimer.pauseWhenSongEnd) playerConnection.player.duration - playerConnection.player.currentPosition else playerConnection.service.sleepTimer.triggerTime - System.currentTimeMillis(); delay(1000L) } }
    if (showDetailsDialog) AlertDialog(properties = DialogProperties(usePlatformDefaultWidth = false), onDismissRequest = { showDetailsDialog = false }, icon = { Icon(painterResource(R.drawable.info), null) }, confirmButton = { TextButton(onClick = { showDetailsDialog = false }) { Text(stringResource(android.R.string.ok)) } }, text = { Column(modifier = Modifier.sizeIn(minWidth = 280.dp, maxWidth = 560.dp).verticalScroll(rememberScrollState())) { listOf(stringResource(R.string.song_title) to mediaMetadata?.title, stringResource(R.string.song_artists) to mediaMetadata?.artists?.joinToString { it.name }, stringResource(R.string.media_id) to mediaMetadata?.id, stringResource(R.string.mime_type) to currentFormat?.mimeType, stringResource(R.string.codecs) to currentFormat?.codecs, stringResource(R.string.bitrate) to currentFormat?.bitrate?.let { "${it / 1000} Kbps" }, stringResource(R.string.sample_rate) to currentFormat?.sampleRate?.let { "$it Hz" }, stringResource(R.string.volume) to "${(playerConnection.player.volume * 100).toInt()}%").forEach { (label, text) -> val displayText = text ?: stringResource(R.string.unknown); Text(label, style = MaterialTheme.typography.labelMedium); Text(displayText, style = MaterialTheme.typography.titleMedium, modifier = Modifier.clickable(interactionSource = remember { MutableInteractionSource() }, indication = null) { clipboardManager.setText(AnnotatedString(displayText)); Toast.makeText(context, R.string.copied, Toast.LENGTH_SHORT).show() }); Spacer(modifier = Modifier.height(8.dp)) } } })
    val openQueue = remember(playerBottomSheetState, state) { { playerBottomSheetState.expandSoft(); state.expandSoft() } }

    BottomSheet(state = state, background = { Box(modifier = Modifier.fillMaxSize().background(backgroundColor)) }, modifier = modifier, collapsedContent = {
        when (playerDesignStyle) {
            1 -> QueueCollapsedContentV1(showCodecOnPlayer, currentFormat, textBackgroundColor, sleepTimerEnabled, sleepTimerTimeLeft, openQueue, { showSleepTimerDialog = true }, { })
            2 -> QueueCollapsedContentV2(showCodecOnPlayer, currentFormat, textBackgroundColor, textBackgroundColor, textBackgroundColor, sleepTimerEnabled, sleepTimerTimeLeft, repeatMode, openQueue, { showSleepTimerDialog = true }, { }, { playerConnection.player.toggleRepeatMode() }, { menuState.show { PlayerMenu(mediaMetadata!!, navController, playerBottomSheetState, onShowDetailsDialog = { showDetailsDialog = true }, onDismiss = { menuState.dismiss() }) } })
            3, 5 -> QueueCollapsedContentV3(showCodecOnPlayer, currentFormat, textBackgroundColor, sleepTimerEnabled, sleepTimerTimeLeft, openQueue, { showSleepTimerDialog = true }, { }, { menuState.show { PlayerMenu(mediaMetadata!!, navController, playerBottomSheetState, onShowDetailsDialog = { showDetailsDialog = true }, onDismiss = { menuState.dismiss() }) } })
            4, 6 -> QueueCollapsedContentV4(showCodecOnPlayer, currentFormat, textBackgroundColor, sleepTimerEnabled, sleepTimerTimeLeft, openQueue, { showSleepTimerDialog = true }, { })
            7, 8 -> QueueCollapsedContentV7(showCodecOnPlayer, currentFormat, textBackgroundColor, sleepTimerEnabled, sleepTimerTimeLeft, openQueue, { }, { showSleepTimerDialog = true }, {}, "Speaker")
            9 -> QueueCollapsedContentV9(showCodecOnPlayer, currentFormat, textBackgroundColor, sleepTimerEnabled, sleepTimerTimeLeft, playerConnection.shuffleModeEnabled.collectAsState().value, repeatMode, { playerConnection.player.shuffleModeEnabled = !playerConnection.player.shuffleModeEnabled }, { playerConnection.player.toggleRepeatMode() }, { menuState.show { PlayerMenu(mediaMetadata!!, navController, playerBottomSheetState, onShowDetailsDialog = { showDetailsDialog = true }, onDismiss = { menuState.dismiss() }) } }, { showSleepTimerDialog = true })
            else -> QueueCollapsedContentV4(showCodecOnPlayer, currentFormat, textBackgroundColor, sleepTimerEnabled, sleepTimerTimeLeft, openQueue, { showSleepTimerDialog = true }, { })
        }
        if (showSleepTimerDialog) SleepTimerDialog({ showSleepTimerDialog = false }, { playerConnection.service.sleepTimer.start(it) }, { showSleepTimerDialog = false; playerConnection.service.sleepTimer.start(-1) }, sleepTimerValue)
    }) {
        val mutableQueueWindows = remember { mutableStateListOf<Timeline.Window>() }
        val queueLength = remember(queueWindows) { queueWindows.sumOf { it.mediaItem.metadata?.duration ?: 0 } }
        val lazyListState = rememberLazyListState()
        var dragInfo by remember { mutableStateOf<Pair<Int, Int>?>(null) }
        val headerItems = 1
        val reorderableState = rememberReorderableLazyListState(lazyListState, scrollThresholdPadding = WindowInsets.systemBars.add(WindowInsets(top = ListItemHeight, bottom = ListItemHeight)).asPaddingValues()) { from, to ->
            dragInfo = (dragInfo?.first ?: from.index) to to.index
            val safeFrom = (from.index - headerItems).coerceIn(0, mutableQueueWindows.lastIndex); val safeTo = (to.index - headerItems).coerceIn(0, mutableQueueWindows.lastIndex)
            mutableQueueWindows.move(safeFrom, safeTo)
        }
        LaunchedEffect(reorderableState.isAnyItemDragging) {
            if (!reorderableState.isAnyItemDragging) dragInfo?.let { (from, to) ->
                val safeFrom = (from - headerItems).coerceIn(0, queueWindows.lastIndex); val safeTo = (to - headerItems).coerceIn(0, queueWindows.lastIndex)
                if (!playerConnection.player.shuffleModeEnabled) playerConnection.player.moveMediaItem(safeFrom, safeTo)
                else playerConnection.player.setShuffleOrder(DefaultShuffleOrder(queueWindows.map { it.firstPeriodIndex }.toMutableList().move(safeFrom, safeTo).toIntArray(), System.currentTimeMillis()))
                dragInfo = null
            }
        }
        LaunchedEffect(queueWindows) { mutableQueueWindows.apply { clear(); addAll(queueWindows) } }
        LaunchedEffect(state.isCollapsed, currentWindowIndex) { if (!state.isCollapsed && currentWindowIndex != -1) lazyListState.scrollToItem(currentWindowIndex + headerItems) }

        Box(modifier = Modifier.fillMaxSize().background(backgroundColor)) {
            Column(modifier = Modifier.fillMaxSize()) {
                CurrentSongHeader(mediaMetadata, currentSong?.song?.liked == true, repeatMode, playerConnection.player.shuffleModeEnabled, locked, queueWindows.size, queueLength, infiniteQueueEnabled, false, backgroundColor, onBackgroundColor, { playerConnection.service.toggleLike() }, { menuState.show { PlayerMenu(mediaMetadata!!, navController, playerBottomSheetState, isQueueTrigger = true, onShowDetailsDialog = { showDetailsDialog = true }, onDismiss = { menuState.dismiss() }) } }, { queueWindows.filterIndexed { i, _ -> i != currentWindowIndex }.forEachIndexed { i, w -> playerConnection.player.removeMediaItem(w.firstPeriodIndex - i) }; clearSelection() }, { playerConnection.player.toggleRepeatMode() }, { playerConnection.player.shuffleModeEnabled = !playerConnection.player.shuffleModeEnabled }, { locked = !locked }, { infiniteQueueEnabled = !infiniteQueueEnabled })
                LazyColumn(state = lazyListState, contentPadding = WindowInsets.systemBars.only(WindowInsetsSides.Bottom + WindowInsetsSides.Horizontal).add(WindowInsets(bottom = ListItemHeight + if (selection) 88.dp else 8.dp)).asPaddingValues(), modifier = Modifier.weight(1f).nestedScroll(state.preUpPostDownNestedScrollConnection)) {
                    item { Spacer(modifier = Modifier.animateContentSize().height(if (selection) 48.dp else 0.dp)) }
                    itemsIndexed(items = mutableQueueWindows, key = { _, item -> item.uid.hashCode() }) { index, window ->
                        ReorderableItem(state = reorderableState, key = window.uid.hashCode()) {
                            val currentItem by rememberUpdatedState(window); val isActive = index == currentWindowIndex
                            val dismissBoxState = rememberSwipeToDismissBoxState(positionalThreshold = { it })
                            var processedDismiss by remember { mutableStateOf(false) }
                            LaunchedEffect(dismissBoxState.currentValue) { val dv = dismissBoxState.currentValue; if (!processedDismiss && (dv == SwipeToDismissBoxValue.StartToEnd || dv == SwipeToDismissBoxValue.EndToStart)) { processedDismiss = true; val idx = currentItem.firstPeriodIndex; playerConnection.player.removeMediaItem(idx); dismissJob?.cancel(); dismissJob = coroutineScope.launch { val res = snackbarHostState.showSnackbar(context.getString(R.string.removed_song_from_playlist, currentItem.mediaItem.metadata?.title), context.getString(R.string.undo), duration = SnackbarDuration.Short); if (res == SnackbarResult.ActionPerformed) { playerConnection.player.addMediaItem(currentItem.mediaItem); playerConnection.player.moveMediaItem(playerConnection.player.mediaItemCount - 1, idx) } } }; if (dv == SwipeToDismissBoxValue.Settled) processedDismiss = false }
                            val content: @Composable () -> Unit = { Row(horizontalArrangement = Arrangement.Center, modifier = Modifier.graphicsLayer { compositingStrategy = androidx.compose.ui.graphics.CompositingStrategy.Offscreen }) { MediaMetadataListItem(mediaMetadata = window.mediaItem.metadata!!, isSelected = selection && window.mediaItem.metadata!! in selectedSongs, isActive = isActive, isPlaying = isPlaying && isActive, trailingContent = { IconButton(onClick = { menuState.show { SelectionMediaMetadataMenu(songSelection = selectedSongs, onDismiss = { menuState.dismiss() }, clearAction = { clearSelection() }, currentItems = selectedItems) } }) { Icon(painterResource(R.drawable.more_vert), null) }; if (!locked) IconButton(onClick = {}, modifier = Modifier.draggableHandle().graphicsLayer { alpha = 0.99f }) { Icon(painterResource(R.drawable.drag_handle), null) } }, modifier = Modifier.fillMaxWidth().background(backgroundColor).combinedClickable(onClick = { if (selection) { if (window.mediaItem.metadata!! in selectedSongs) { selectedSongs.remove(window.mediaItem.metadata!!); selectedItems.remove(currentItem); if (selectedSongs.isEmpty()) selection = false } else { selectedSongs.add(window.mediaItem.metadata!!); selectedItems.add(currentItem) } } else { if (index == currentWindowIndex) playerConnection.player.togglePlayPause() else { playerConnection.player.seekToDefaultPosition(window.firstPeriodIndex); playerConnection.player.playWhenReady = true } } }, onLongClick = { if (enableHapticFeedback) haptic.performHapticFeedback(HapticFeedbackType.LongPress); selection = true; selectedSongs.clear(); selectedItems.clear(); selectedSongs.add(window.mediaItem.metadata!!); selectedItems.add(currentItem) })) } }
                            if (locked) content() else SwipeToDismissBox(state = dismissBoxState, backgroundContent = {}) { content() }
                        }
                    }
                    if (automix.isNotEmpty()) {
                        item { HorizontalDivider(modifier = Modifier.padding(vertical = 8.dp, horizontal = 4.dp)); ItemWithGlowingIcon() }
                        itemsIndexed(items = automix, key = { _, it -> it.mediaId }) { index, item -> Row(horizontalArrangement = Arrangement.Center) { MediaMetadataListItem(mediaMetadata = item.metadata!!, trailingContent = { IconButton(onClick = { playerConnection.service.playNextAutomix(item, index) }) { Icon(painterResource(R.drawable.playlist_play), null) }; IconButton(onClick = { playerConnection.service.addToQueueAutomix(item, index) }) { Icon(painterResource(R.drawable.queue_music), null) } }, modifier = Modifier.fillMaxWidth().combinedClickable(onClick = {}, onLongClick = { menuState.show { PlayerMenu(mediaMetadata = item.metadata!!, navController = navController, playerBottomSheetState = playerBottomSheetState, isQueueTrigger = true, onShowDetailsDialog = { showDetailsDialog = true }, onDismiss = { menuState.dismiss() }) } }).animateItem()) } }
                    }
                }
            }
            Box(modifier = Modifier.fillMaxSize()) {
                SnackbarHost(hostState = snackbarHostState, modifier = Modifier.padding(bottom = (if (selection) ListItemHeight * 2 + 16.dp else ListItemHeight) + WindowInsets.systemBars.asPaddingValues().calculateBottomPadding()).align(Alignment.BottomCenter))
                AnimatedVisibility(visible = selection, enter = fadeIn() + expandVertically(expandFrom = Alignment.Bottom), exit = fadeOut() + shrinkVertically(shrinkTowards = Alignment.Bottom), modifier = Modifier.align(Alignment.BottomCenter).padding(bottom = ListItemHeight + WindowInsets.systemBars.asPaddingValues().calculateBottomPadding())) {
                    QueueSelectionFloatingToolbar(selectedSongs.size == mutableQueueWindows.size, backgroundColor == Color.Black, ::clearSelection, { if (selectedSongs.size == mutableQueueWindows.size) clearSelection() else { selectedSongs.clear(); selectedItems.clear(); mutableQueueWindows.forEach { w -> selectedSongs.add(w.mediaItem.metadata!!); selectedItems.add(w) } } }, { menuState.show { SelectionMediaMetadataMenu(songSelection = selectedSongs, onDismiss = { menuState.dismiss() }, clearAction = { clearSelection() }, currentItems = selectedItems) } }, { val sorted = selectedItems.sortedBy { it.firstPeriodIndex }; var i = 0; sorted.forEach { playerConnection.player.removeMediaItem(it.firstPeriodIndex - i++) }; clearSelection() }, modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp))
                }
            }
        }
    }
}

