    val cs = MaterialTheme.colorScheme
    HorizontalFloatingToolbar(expanded = true, modifier = modifier.widthIn(max = 420.dp), floatingActionButton = { FloatingToolbarDefaults.VibrantFloatingActionButton(onClick = onClose, containerColor = if (pureBlack) Color.White.copy(0.12f) else cs.surfaceContainerHighest, contentColor = if (pureBlack) Color.White else cs.onSurface) { Icon(painterResource(R.drawable.close), null, modifier = Modifier.size(22.dp)) } }, colors = FloatingToolbarDefaults.standardFloatingToolbarColors(toolbarContainerColor = if (pureBlack) Color.Black else cs.surfaceContainerHigh)) { Row(modifier = Modifier.heightIn(min = 56.dp).padding(horizontal = 8.dp, vertical = 6.dp), horizontalArrangement = Arrangement.spacedBy(4.dp), verticalAlignment = Alignment.CenterVertically) { QueueSelectionToolbarAction(icon = if (allSelected) R.drawable.deselect else R.drawable.select_all, desc = null, onClick = onToggleSelectAll, tint = if (pureBlack) Color.White else cs.onSurface); QueueSelectionToolbarAction(icon = R.drawable.more_vert, desc = null, onClick = onMenuAction, tint = cs.primary); QueueSelectionToolbarAction(icon = R.drawable.delete, desc = stringResource(R.string.delete), onClick = onDelete, tint = cs.error) } }
