        Spacer(modifier = Modifier.height(14.dp))
        Row(modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(24.dp)).background(onBackgroundColor.copy(0.06f)).padding(horizontal = 6.dp, vertical = 4.dp), verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween) { Row(verticalAlignment = Alignment.CenterVertically) { IconButton(onClick = onLockClick, modifier = Modifier.size(40.dp), colors = IconButtonDefaults.iconButtonColors(contentColor = onBackgroundColor.copy(0.7f))) { Icon(painterResource(if (locked) R.drawable.lock else R.drawable.lock_open), null, modifier = Modifier.size(20.dp)) }; IconButton(onClick = onMenuClick, modifier = Modifier.size(40.dp), colors = IconButtonDefaults.iconButtonColors(contentColor = onBackgroundColor.copy(0.7f))) { Icon(painterResource(R.drawable.more_vert), null, modifier = Modifier.size(20.dp)) }; IconButton(onClick = onClearQueueClick, modifier = Modifier.size(40.dp), colors = IconButtonDefaults.iconButtonColors(contentColor = MaterialTheme.colorScheme.error)) { Icon(painterResource(R.drawable.delete), null, modifier = Modifier.size(20.dp)) } }; Text(pluralStringResource(R.plurals.n_song, songCount, songCount) + "  •  " + makeTimeString(queueDuration * 1000L), style = MaterialTheme.typography.labelMedium, color = onBackgroundColor.copy(0.55f), modifier = Modifier.padding(end = 14.dp)) }
        Spacer(modifier = Modifier.height(14.dp))
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(ButtonGroupDefaults.ConnectedSpaceBetween), verticalAlignment = Alignment.CenterVertically) { val uc = ToggleButtonDefaults.toggleButtonColors(containerColor = onBackgroundColor.copy(0.12f), contentColor = onBackgroundColor); val cc = ToggleButtonDefaults.toggleButtonColors(checkedContainerColor = onBackgroundColor.copy(0.22f), checkedContentColor = onBackgroundColor); val ic = ToggleButtonDefaults.toggleButtonColors(checkedContainerColor = MaterialTheme.colorScheme.primary, checkedContentColor = MaterialTheme.colorScheme.onPrimary, containerColor = onBackgroundColor.copy(0.12f), contentColor = onBackgroundColor.copy(0.5f)); ToggleButton(checked = shuffleModeEnabled, onCheckedChange = { onShuffleClick() }, modifier = Modifier.weight(1f).size(48.dp), shapes = ButtonGroupDefaults.connectedLeadingButtonShapes(), colors = if (shuffleModeEnabled) cc else uc) { Icon(painterResource(R.drawable.shuffle), null, modifier = Modifier.size(22.dp)) }; ToggleButton(checked = repeatMode != Player.REPEAT_MODE_OFF, onCheckedChange = { onRepeatClick() }, modifier = Modifier.weight(1f).size(48.dp), shapes = ButtonGroupDefaults.connectedMiddleButtonShapes(), colors = if (repeatMode != Player.REPEAT_MODE_OFF) cc else uc) { Icon(painterResource(when (repeatMode) { Player.REPEAT_MODE_ONE -> R.drawable.repeat_one; else -> R.drawable.repeat }), null, modifier = Modifier.size(22.dp)) }; ToggleButton(checked = infiniteQueueEnabled, onCheckedChange = { onInfiniteQueueClick() }, modifier = Modifier.weight(1f).size(48.dp), shapes = ButtonGroupDefaults.connectedTrailingButtonShapes(), colors = ic, enabled = !infiniteQueueLoading) { AnimatedContent(targetState = infiniteQueueLoading, label = "") { if (it) CircularProgressIndicator(modifier = Modifier.size(22.dp), color = LocalContentColor.current, strokeWidth = 2.dp) else Icon(painterResource(R.drawable.queue_music), null, modifier = Modifier.size(22.dp)) } } }
        Spacer(modifier = Modifier.height(14.dp)); Text("Continue playing", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold, color = onBackgroundColor); Spacer(modifier = Modifier.height(2.dp)); Text("Autoplaying similar content", style = MaterialTheme.typography.bodySmall, color = onBackgroundColor.copy(0.5f)); Spacer(modifier = Modifier.height(12.dp)); HorizontalDivider(color = onBackgroundColor.copy(0.08f), thickness = 1.dp)
    }
}

